const board=document.getElementById('taskBoard');

function escAttr(v){
 return String(v ?? '').replace(/"/g,'&quot;');
}

function renderBoard(){
 if(!board) return;

 const headHtml = `
  <div class="task-grid task-grid--head">
    <div class="task-cell task-cell--task task-cell--head task-cell--task-head">Задача</div>
    ${PO.map((po,i)=>`
      <div class="task-cell task-cell--head task-cell--protocol">
        <div class="task-po">${po}</div>
        <div class="task-date">${PD2[i]}</div>
        <div class="task-date task-date--short">${PD[i]}</div>
      </div>
    `).join('')}
  </div>
 `;

 const sectionsHtml = CATS.map(cat => `
  <section class="task-section" style="--section-color:${cat.col};">
    <div class="task-section-title">${cat.name}</div>
    <div class="task-grid">
      ${cat.tasks.map(task => `
        <button type="button" class="task-cell task-cell--task task-row-anchor" data-task-id="${task.id}" onclick="sel('${task.id}')">
          <span class="task-name">${escapeHtml(task.name)}</span>
        </button>
        ${PO.map((po,i)=>{
          const pd = task.po[po];
          if(!pd){
            return `
              <button type="button" class="task-cell task-status task-status--empty task-row-anchor" data-task-id="${task.id}" onclick="sel('${task.id}')">
                <span class="task-status-empty">—</span>
              </button>
            `;
          }
          const s = SC[pd.s] || SC['НА ИСПОЛНЕНИИ'];
          return `
            <button
              type="button"
              class="task-cell task-status task-row-anchor"
              data-task-id="${task.id}"
              data-status="${escAttr(pd.s)}"
              onclick="sel('${task.id}')"
              style="--status-color:${s.c};"
              aria-label="${escAttr(`${task.name} · ${po} · ${pd.s}`)}"
            >
              <span class="task-status-mark">${s.m}</span>
              <span class="task-status-label">${escapeHtml(pd.s)}</span>
            </button>
          `;
        }).join('')}
      `).join('')}
    </div>
  </section>
 `).join('');

 board.innerHTML = headHtml + sectionsHtml;
}

renderBoard();

// Interaction
let curId=null;

function setTaskSelection(taskId, selected){
 const nodes=document.querySelectorAll(`[data-task-id="${taskId}"]`);
 nodes.forEach((node)=>node.classList.toggle('is-selected', selected));
}

function escapeHtml(v){
 return String(v ?? '')
   .replace(/&/g,'&amp;')
   .replace(/</g,'&lt;')
   .replace(/>/g,'&gt;')
   .replace(/"/g,'&quot;')
   .replace(/'/g,'&#39;');
}

function extractDateLabel(text){
 const patterns = [
   /\b\d{2}\.\d{2}\.\d{4}\s*г?\.?/,
   /\b\d{2}\.\d{2}\.\d{4}\b/,
   /\b\d{1,2}\s+[а-яё]+\s+\d{4}\s+года\b/i,
   /\b\d{1,2}\s+[а-яё]+\s+\d{4}\b/i
 ];
 for(const rx of patterns){
   const m = text.match(rx);
   if(m) return m[0].replace(/\s+/g,' ').trim();
 }
 return '';
}

function formatProgress(raw){
 if(!raw) return '—';
 const normalized = String(raw).replace(/\r/g,'').trim();
 if(!normalized) return '—';

 let blocks = normalized.split(/\n{2,}/).map(v=>v.trim()).filter(Boolean);

 if(blocks.length === 1){
   const lines = normalized.split('\n').map(v=>v.trim()).filter(Boolean);
   if(lines.length > 1){
     const grouped = [];
     let current = [];
     const starter = /^([0-9]+(?:\.[0-9]+)*\.?\s*[—-]|[А-ЯЁA-Z][^a-zа-яё]{1,40}$|(?:МНЭ|МПС|АО|ТОО|СКК)\b)/;
     for(const line of lines){
       if(current.length && starter.test(line)) {
         grouped.push(current.join('\n'));
         current = [line];
       } else {
         current.push(line);
       }
     }
     if(current.length) grouped.push(current.join('\n'));
     if(grouped.length > 1) blocks = grouped;
   }
 }

 return blocks.map((block, index)=>{
   const date = extractDateLabel(block);
   const safe = escapeHtml(block).replace(/\n/g,'<br>');
   const dateHtml = date ? `<div class="progress-date">${escapeHtml(date)}</div>` : '';
   return `<div class="progress-item">${dateHtml}<span class="progress-index">${index + 1})</span>${safe}</div>`;
 }).join('');
}

function sel(id){
 if(curId){
  setTaskSelection(curId, false);
 }
 curId=id;
 setTaskSelection(id, true);
 // find task
 let task=null;
 for(const c of CATS){for(const t of c.tasks){if(t.id===id){task={...t,catName:c.name,catCol:c.col};break;}}if(task)break;}
 if(!task)return;
 // top bar
 const dtop=document.getElementById('dtop');
 dtop.innerHTML=`<div style="display:flex;align-items:flex-start;gap:10px;width:100%;">
   <span style="width:10px;height:10px;border-radius:50%;background:${task.catCol};display:inline-block;flex-shrink:0;margin-top:4px;"></span>
   <div style="display:flex;flex-direction:column;gap:2px;min-width:0;flex:1;">
     <span style="color:var(--color-text-secondary);font-size:11px;">${task.catName}</span>
     <span style="color:var(--color-text-primary);font-size:14px;font-weight:600;line-height:1.35;word-break:break-word;">${task.name}</span>
   </div>
</div>`;
 renderTaskStats(id);
 // grid
 const grid=document.getElementById('det-grid');
 let html='';
 PO.forEach((p,i)=>{
  const pd=task.po[p];
  if(pd){
   const s=SC[pd.s]||SC['НА ИСПОЛНЕНИИ'];
   html+=`<div class="detail-card" style="border:0.5px solid ${s.c};background:${s.c}14;">
    <div class="detail-card-title">${p}</div>
    <div class="detail-card-date">${PD2[i]} · ${PD[i]}</div>
    <div class="detail-card-status" style="color:${s.c};">${pd.s}</div>
    <div class="detail-card-row"><b>Пункт:</b> ${pd.p}</div>
    <div class="detail-card-row"><b>Что поручено:</b> ${pd.task || '—'}</div>
    <div class="detail-card-row"><b>Срок:</b> ${pd.d || '—'}</div>
    <div class="detail-card-row"><b>Отв.:</b> ${pd.o}</div>
    <div class="detail-card-row"><b>Ход исполнения:</b><div class="progress-list">${formatProgress(pd.n)}</div></div>
   </div>`;
  }else{
   html+=`<div class="detail-card" style="border:0.5px solid var(--color-border-tertiary);opacity:0.55;background:#FFFFFF;">
    <div class="detail-card-title">${p}</div>
    <div class="detail-card-date">${PD2[i]} · ${PD[i]}</div>
    <div class="detail-card-row" style="font-style:italic;">Не упоминается в этом протоколе</div>
   </div>`;
  }
 });
 grid.innerHTML=html;
 document.getElementById('modalOverlay').classList.add('is-open');
 document.body.classList.add('modal-open');
}
function closeD(){
 document.getElementById('modalOverlay').classList.remove('is-open');
 document.body.classList.remove('modal-open');
 if(curId){setTaskSelection(curId, false);}
 curId=null;
}

function setDetailScale(scale){
 const value = Math.max(0.95, Math.min(1.4, Number(scale) || 1));
 const normalized = (Math.round(value * 100) / 100).toString();
 document.documentElement.style.setProperty('--detail-font-scale', normalized);
 try { localStorage.setItem('meks_detail_scale', normalized); } catch(e) {}

 const range = document.getElementById('detailFontRange');
 if(range) range.value = String(Math.round(value * 100));

 const valueLabel = document.getElementById('detailScaleValue');
 if(valueLabel) valueLabel.textContent = `${Math.round(value * 100)}%`;
}
(function initDetailScale(){
 let saved = '1';
 try { saved = localStorage.getItem('meks_detail_scale') || '1'; } catch(e) {}
 const value = Number(saved);
 setDetailScale(Number.isFinite(value) ? value : 1);
})();

document.addEventListener('keydown', (event) => {
 if(event.key === 'Escape'){ closeStatusModal(); closeD(); }
});

document.getElementById('modalOverlay')?.addEventListener('click', (event) => {
 if(event.target && event.target.id === 'modalOverlay') closeD();
});


const TODAY_REF = new Date('2026-04-20T00:00:00');
function parseRuDate(s){
 if(!s) return null;
 const m=String(s).match(/(\d{2})\.(\d{2})\.(\d{4})/);
 if(!m) return null;
 return new Date(`${m[3]}-${m[2]}-${m[1]}T00:00:00`);
}
const PROTOCOL_DATE_MAP = Object.fromEntries(PO.map((p,i)=>[p, PD2[i]]));
function isLongRunning(record){
 if(!record || record.status!=='НА ИСПОЛНЕНИИ') return false;
 const dt = parseRuDate(record.date);
 if(!dt) return false;
 const diffDays = Math.floor((TODAY_REF - dt) / 86400000);
 return diffDays >= 60;
}
function flattenEntries(taskId=null){
 const entries=[];
 for(const c of CATS){
  for(const t of c.tasks){
   if(taskId && t.id!==taskId) continue;
   for(const p of PO){
    const pd=t.po[p];
    if(!pd) continue;
    entries.push({
      taskId: t.id,
      taskName: t.name,
      categoryName: c.name,
      categoryColor: c.col,
      protocol: p,
      date: PROTOCOL_DATE_MAP[p] || '',
      status: pd.s || '',
      point: pd.p || '—',
      assignedTask: pd.task || '—',
      deadline: pd.d || '—',
      responsibleRaw: pd.o || '—',
      progress: pd.n || '—'
    });
   }
  }
 }
 return entries;
}
function countStats(entries){
 return {
   process: entries.filter(x=>x.status==='НА ИСПОЛНЕНИИ').length,
   overdue: entries.filter(x=>isLongRunning(x)).length,
   notdone: entries.filter(x=>x.status==='НЕ ИСПОЛНЕНО').length
 };
}
function escHtml(v){
 return String(v ?? '').replace(/[&<>"']/g, s => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[s]));
}
function nl2br(v){
 return escHtml(v).replace(/\n/g,'<br>');
}
function buildStatChips(stats, scope){
 const defs = [
   ['process','На исполнении'],
   ['overdue','Тянутся давно'],
   ['notdone','Не исполнено']
 ];
 return defs.map(([key,label]) =>
   `<button type="button" class="stat-chip ${key}" onclick="openStatusModal('${key}','${scope}')">
      <span>${label}</span>
      <span class="num">${stats[key] || 0}</span>
    </button>`
 ).join('');
}
function renderGlobalStats(){
 const stats=countStats(flattenEntries());
 const box=document.getElementById('globalStatsBar');
 if(box) box.innerHTML=buildStatChips(stats,'global');
}
function renderTaskStats(taskId){
 const box=document.getElementById('taskStatsBar');
 if(!box) return;
 const stats=countStats(flattenEntries(taskId));
 box.innerHTML=buildStatChips(stats, taskId);
}
function statusLabelByKey(key){
 return ({process:'На исполнении', overdue:'Тянутся давно', notdone:'Не исполнено'})[key] || 'Задачи';
}
function filterEntriesByKey(entries,key){
 if(key==='process') return entries.filter(x=>x.status==='НА ИСПОЛНЕНИИ');
 if(key==='overdue') return entries.filter(x=>isLongRunning(x));
 if(key==='notdone') return entries.filter(x=>x.status==='НЕ ИСПОЛНЕНО');
 return entries;
}
function formatResponsibleBlock(raw){
 const clean = raw && raw.trim() ? raw.trim() : 'не указано';
 return `
  <div class="status-item-row"><b>Ответственный:</b> ${nl2br(clean)}</div>
  <div class="status-item-row"><b>ФИО / должность:</b> не указаны в предоставленном протоколе</div>
  <div class="status-item-row"><b>Ведомство / организация:</b> ${nl2br(clean)}</div>
 `;
}
function openStatusModal(key, scope='global'){
 const all = scope==='global' ? flattenEntries() : flattenEntries(scope);
 const filtered = filterEntriesByKey(all, key);
 const title = `${statusLabelByKey(key)} · ${filtered.length}`;
 const titleNode=document.getElementById('statusModalTitle');
 const listNode=document.getElementById('statusModalList');
 if(titleNode) titleNode.textContent = title;
 if(!listNode) return;
 if(!filtered.length){
   listNode.innerHTML = `<div class="status-item"><div class="status-item-row">По выбранному фильтру задач не найдено.</div></div>`;
 } else {
   listNode.innerHTML = filtered.map(item=>{
     const badgeColor = key==='notdone' ? '#DC2626' : key==='overdue' ? '#D97706' : '#2563EB';
     return `<div class="status-item">
       <div class="status-item-head">
         <span class="status-badge" style="background:${badgeColor};">${escHtml(item.status)}</span>
         <span style="width:10px;height:10px;border-radius:50%;background:${escHtml(item.categoryColor)};display:inline-block;"></span>
         <span><b>${escHtml(item.taskName)}</b></span>
         <span class="status-meta">${escHtml(item.categoryName)}</span>
       </div>
       <div class="status-item-row"><b>Что за задача:</b> ${nl2br(item.assignedTask)}</div>
       <div class="status-item-row"><b>Когда поручена:</b> ${escHtml(item.date)} · ${escHtml(item.protocol)} · ${escHtml(item.point)}</div>
       <div class="status-item-row"><b>Срок:</b> ${nl2br(item.deadline)}</div>
       ${formatResponsibleBlock(item.responsibleRaw)}
       <div class="status-item-row"><b>Причины неисполнения и / или длительного исполнения:</b><br>${formatProgress(item.progress)}</div>
     </div>`;
   }).join('');
 }
 document.getElementById('statusModalOverlay').classList.add('is-open');
 document.body.classList.add('modal-open');
}
function closeStatusModal(){
 document.getElementById('statusModalOverlay').classList.remove('is-open');
 document.body.classList.remove('modal-open');
}
